// Script Continued Below
// 2.8.3 (Template Updates Addon) STRY0142161 - Feature allowing for Templates to be copied/cloned
(function process(/*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

	var requestBody = request.body;
	var metaDataString = requestBody;
	var objMetaData = JSON.parse(requestBody.dataString);

	var responseObj = _isTemplateNameUnique(objMetaData);

	response.setBody(responseObj);

	response.setStatus(200);
	response.setContentType('application/json');


	function _isTemplateNameUnique(metaData){
		var apiTaskerTemplate = new api_tasker_template();
		var templateNameUnique=false;
		var validMetaData = apiTaskerTemplate.validateNameCheckMetaData("template_api.isTemplateNameUnique", metaData);
		if(validMetaData.validCallData){
			templateNameUnique = apiTaskerTemplate.isTemplateNameUnique(validMetaData.new_template_name, 
									validMetaData.template_level, validMetaData.template_ou, validMetaData.template_owner);
			metaData.success = true;
			metaData.isTemplateNameUnique = templateNameUnique;
		}  // note, if invalid call data, success is set to false inside metadata check
		return metaData;

	}

})(request, response);
